def foo(str):
    newStr = ''
    for i in range(len(str) - 1, -1, -1):
        newStr += str[i]
    return newStr

def foo(str):
    arr = str.split(' ')
    for i in range(len(arr)):
        arr[i] = arr[i].capitalize()
    return ' '.join(arr)

def foo(str):
    newStr = ''
    for i in str:
        if i not in newStr:
            newStr += i
    return newStr
